import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.io.IOException;
import java.io.PrintWriter;

public class SecureCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!')</script>";

        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<head><title>Secure Code</title></head>");
        out.println("<body>");

        try {
            // Properly encode user input to prevent XSS
            String encodedInput = ESAPI.encoder().encodeForHTML(userInput);
            out.println("User Input: " + encodedInput);
        } catch (EncodingException e) {
            // Handle encoding exception
            System.err.println("Error encoding user input");
        }

        out.println("</body>");
        out.println("</html>");

        out.flush();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
